  "security_privacy_desc": { en: "Every contribution record is the 'secret' of the event owner.", kh: "бһҡбһ¶бһӣбҹӢбһ‘бһ·бһ“бҹ’бһ“бһ“бҹҗбһҷбһ…бҹҶбһҺбһ„бһҠбҹғ бһӮбһәбһҮбһ¶ \"бһўбһ¶бһҗбҹҢбһҖбҹҶбһ”бһ¶бҹҶбһ„\" бһҡбһ”бһҹбҹӢбһҳбҹ’бһ…бһ¶бһҹбҹӢбһҖбһҳбҹ’бһҳбһңбһ·бһ’бһёбҹ”" },
  "admin_privacy": { en: "Admin: Only the event owner can see figures and guest lists.", kh: "бһ•бҹ’бһ“бҹӮбһҖ Admin: бһҳбһ¶бһ“бһҸбҹӮбһҳбҹ’бһ…бһ¶бһҹбҹӢбһҖбһҳбҹ’бһҳбһңбһ·бһ’бһёбһ”бҹүбһ»бһҺбҹ’бһҺбҹ„бҹҮбһҠбҹӮбһӣбһўбһ¶бһ…бһҳбһҫбһӣбһғбһҫбһүбһҸбһҪбһӣбҹҒбһҒ бһ“бһ·бһ„бһ”бһүбҹ’бһҮбһёбһҲбҹ’бһҳбҹ„бҹҮбҹ”" },
  "public_privacy": { en: "Public: Guests can only see event info, map, and QR Code for participation.", kh: "бһ•бҹ’бһ“бҹӮбһҖ Public: бһ—бҹ’бһүбҹҖбһңбһўбһ¶бһ…бһҳбһҫбһӣбһғбһҫбһүбһҸбҹӮбһ–бҹҗбһҸбҹҢбһҳбһ¶бһ“бһҖбһҳбҹ’бһҳбһңбһ·бһ’бһё бһ•бҹӮбһ“бһ‘бһё бһ“бһ·бһ„ QR Code бһҹбһҳбҹ’бһҡбһ¶бһ”бҹӢбһ…бһјбһӣбһҡбһҪбһҳбһ”бҹүбһ»бһҺбҹ’бһҺбҹ„бҹҮбҹ”" },
  
  "team_title": { en: "The Team", kh: "бһўбҹҶбһ–бһёбһҖбҹ’бһҡбһ»бһҳбһҖбһ¶бһҡбһ„бһ¶бһҡ" },
  "team_desc": { en: "Created by Khmer children who love technology and want to preserve the culture of reciprocity to remain in the digital age.", kh: "бһ”бһ„бҹ’бһҖбһҫбһҸбһЎбһҫбһ„бһҠбҹ„бһҷбһҖбһјбһ“бһҒбҹ’бһҳбҹӮбһҡ бһҠбҹӮбһӣбһҹбҹ’бһҡбһӣбһ¶бһүбҹӢбһ”бһ…бҹ’бһ…бҹҒбһҖбһңбһ·бһ‘бҹ’бһҷбһ¶ бһ“бһ·бһ„бһ…бһ„бҹӢбһҗбҹӮбһҡбһҖбҹ’бһҹбһ¶бһңбһ”бҹ’бһ”бһ’бһҳбҹҢбһ“бҹғбһҖбһ¶бһҡбһҮбһҪбһҷбһӮбҹ’бһ“бһ¶бһ‘бҹ…бһңбһ·бһүбһ‘бҹ…бһҳбһҖ (Reciprocity) бһұбҹ’бһҷбһ“бҹ…бһӮбһ„бҹӢбһңбһ„бҹ’бһҹбһҸбһ¶бһҳбһҹбһҳбҹҗбһҷбһҖбһ¶бһӣбһҢбһёбһҮбһёбһҗбһӣбҹ”" },

